using System.ComponentModel.DataAnnotations;

namespace VetClinic.Data.Models;

public class Owner
{
    public int Id { get; set; }

    [Required, MaxLength(100)]
    public string FirstName { get; set; } = string.Empty;

    [Required, MaxLength(100)]
    public string LastName { get; set; } = string.Empty;

    [Phone]
    public string? Phone { get; set; }

    [EmailAddress]
    public string? Email { get; set; }

    public string FullName => $"{FirstName} {LastName}";

    public List<Pet> Pets { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace VetClinic.Data.Models;

public class Pet
{
    public int Id { get; set; }

    [Required, MaxLength(100)]
    public string Name { get; set; } = string.Empty;

    [Required, MaxLength(50)]
    public string Species { get; set; } = string.Empty;

    [MaxLength(50)]
    public string? Breed { get; set; }

    public DateOnly? DateOfBirth { get; set; }

    public double? WeightKg { get; set; }

    [MaxLength(20)]
    public string? Microchip { get; set; }

    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;

    public List<TreatmentNote> TreatmentNotes { get; set; } = [];
    public List<Appointment> Appointments { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace VetClinic.Data.Models;

public class TreatmentNote
{
    public int Id { get; set; }

    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;

    public DateTime Date { get; set; } = DateTime.UtcNow;

    [Required, MaxLength(200)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [MaxLength(100)]
    public string? Veterinarian { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace VetClinic.Data.Models;

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled
}

public class Appointment
{
    public int Id { get; set; }

    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;

    [Required]
    public DateTime StartTime { get; set; }

    public DateTime EndTime { get; set; }

    [Required, MaxLength(200)]
    public string Reason { get; set; } = string.Empty;

    [MaxLength(100)]
    public string? Veterinarian { get; set; }

    public AppointmentStatus Status { get; set; } = AppointmentStatus.Scheduled;

    [MaxLength(500)]
    public string? Notes { get; set; }
}

using System.ComponentModel.DataAnnotations;
using System.ComponentModel.DataAnnotations.Schema;

namespace VetClinic.Data.Models;

public enum InvoiceStatus
{
    Pending,
    Paid,
    PartiallyPaid,
    Cancelled
}

public class Invoice
{
    public int Id { get; set; }

    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;

    public int? AppointmentId { get; set; }
    public Appointment? Appointment { get; set; }

    public DateTime CreatedDate { get; set; } = DateTime.UtcNow;

    public DateTime? DueDate { get; set; }

    public InvoiceStatus Status { get; set; } = InvoiceStatus.Pending;

    public List<InvoiceLineItem> LineItems { get; set; } = [];
    public List<Payment> Payments { get; set; } = [];

    [NotMapped]
    public decimal Total => LineItems.Sum(li => li.Amount * li.Quantity);

    [NotMapped]
    public decimal AmountPaid => Payments.Where(p => !p.IsRefunded).Sum(p => p.Amount);

    [NotMapped]
    public decimal Balance => Total - AmountPaid;
}

public class InvoiceLineItem
{
    public int Id { get; set; }

    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;

    [Required, MaxLength(200)]
    public string Description { get; set; } = string.Empty;

    [Column(TypeName = "decimal(10,2)")]
    public decimal Amount { get; set; }

    public int Quantity { get; set; } = 1;
}

using System.ComponentModel.DataAnnotations;
using System.ComponentModel.DataAnnotations.Schema;

namespace VetClinic.Data.Models;

public enum PaymentMethod
{
    Cash,
    CreditCard,
    DebitCard,
    Check,
    BankTransfer
}

public class Payment
{
    public int Id { get; set; }

    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;

    [Column(TypeName = "decimal(10,2)")]
    public decimal Amount { get; set; }

    public PaymentMethod Method { get; set; }

    public DateTime PaidDate { get; set; } = DateTime.UtcNow;

    [MaxLength(200)]
    public string? Reference { get; set; }

    public bool IsRefunded { get; set; }
}

