using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext db)
{
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var query = db.Owners.Include(o => o.Pets).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.ToLower();
            query = query.Where(o => o.FirstName.ToLower().Contains(search)
                || o.LastName.ToLower().Contains(search)
                || o.Pets.Any(p => p.Name.ToLower().Contains(search)));
        }
        return await query.OrderBy(o => o.LastName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);

    public async Task<Owner> SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0)
            db.Owners.Add(owner);
        else
            db.Owners.Update(owner);
        await db.SaveChangesAsync();
        return owner;
    }

    public async Task<Pet?> GetPetAsync(int id) =>
        await db.Pets.Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task<List<Pet>> GetAllPetsAsync() =>
        await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();

    public async Task<Pet> SavePetAsync(Pet pet)
    {
        if (pet.Id == 0)
            db.Pets.Add(pet);
        else
            db.Pets.Update(pet);
        await db.SaveChangesAsync();
        return pet;
    }

    public async Task<TreatmentNote> AddTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
        return note;
    }

    public async Task<TreatmentNote> UpdateTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
        return note;
    }

    public async Task DeleteTreatmentNoteAsync(int id)
    {
        var note = await db.TreatmentNotes.FindAsync(id);
        if (note != null)
        {
            db.TreatmentNotes.Remove(note);
            await db.SaveChangesAsync();
        }
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
    {
        var query = db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue)
            query = query.Where(a => a.StartTime >= from.Value);
        if (to.HasValue)
            query = query.Where(a => a.StartTime <= to.Value);
        return await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);

    public async Task<Appointment> SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0)
            db.Appointments.Add(appointment);
        else
            db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var apt = await db.Appointments.FindAsync(id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<Appointment>> GetAvailabilitySlotsAsync(DateTime date)
    {
        var dayStart = date.Date;
        var dayEnd = dayStart.AddDays(1);
        return await db.Appointments
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<bool> IsSlotAvailableAsync(DateTime start, DateTime end, int? excludeId = null)
    {
        var query = db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled
                && a.StartTime < end && a.EndTime > start);
        if (excludeId.HasValue)
            query = query.Where(a => a.Id != excludeId.Value);
        return !await query.AnyAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? statusFilter = null)
    {
        var query = db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .AsQueryable();
        if (statusFilter.HasValue)
            query = query.Where(i => i.Status == statusFilter.Value);
        return await query.OrderByDescending(i => i.CreatedDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .Include(i => i.Appointment)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Invoice> UpdateInvoiceAsync(Invoice invoice)
    {
        db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddLineItemAsync(InvoiceLineItem item)
    {
        db.InvoiceLineItems.Add(item);
        await db.SaveChangesAsync();
        await UpdateInvoiceStatusAsync(item.InvoiceId);
    }

    public async Task RemoveLineItemAsync(int id)
    {
        var item = await db.InvoiceLineItems.FindAsync(id);
        if (item != null)
        {
            var invoiceId = item.InvoiceId;
            db.InvoiceLineItems.Remove(item);
            await db.SaveChangesAsync();
            await UpdateInvoiceStatusAsync(invoiceId);
        }
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        await db.SaveChangesAsync();
        await UpdateInvoiceStatusAsync(payment.InvoiceId);
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? ownerId = null)
    {
        var query = db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .AsQueryable();
        if (ownerId.HasValue)
            query = query.Where(p => p.Invoice.OwnerId == ownerId.Value);
        return await query.OrderByDescending(p => p.PaidDate).ToListAsync();
    }

    private async Task UpdateInvoiceStatusAsync(int invoiceId)
    {
        var invoice = await db.Invoices
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == invoiceId);

        if (invoice == null) return;

        if (invoice.Balance <= 0 && invoice.Total > 0)
            invoice.Status = InvoiceStatus.Paid;
        else if (invoice.AmountPaid > 0)
            invoice.Status = InvoiceStatus.PartiallyPaid;
        else
            invoice.Status = InvoiceStatus.Pending;

        await db.SaveChangesAsync();
    }
}

