@page "/"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Services
@using VetClinic.Data.Models
@attribute [Authorize]
@rendermode InteractiveServer
@inject PatientService PatientService
@inject AppointmentService AppointmentService
@inject BillingService BillingService

<PageTitle>VetClinic Dashboard</PageTitle>

<h1>🐾 Veterinary Clinic Dashboard</h1>

@if (loading)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="row mt-4">
        <div class="col-md-3">
            <div class="card text-bg-primary mb-3">
                <div class="card-body">
                    <h5 class="card-title">Patients</h5>
                    <p class="card-text display-6">@petCount</p>
                    <a href="patients" class="btn btn-light btn-sm">View All</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-success mb-3">
                <div class="card-body">
                    <h5 class="card-title">Today's Appointments</h5>
                    <p class="card-text display-6">@todayAppointments</p>
                    <a href="appointments" class="btn btn-light btn-sm">Calendar</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-warning mb-3">
                <div class="card-body">
                    <h5 class="card-title">Pending Invoices</h5>
                    <p class="card-text display-6">@pendingInvoices</p>
                    <a href="billing" class="btn btn-light btn-sm">View Billing</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-info mb-3">
                <div class="card-body">
                    <h5 class="card-title">Owners</h5>
                    <p class="card-text display-6">@ownerCount</p>
                    <a href="patients" class="btn btn-light btn-sm">Manage</a>
                </div>
            </div>
        </div>
    </div>

    <div class="row mt-3">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">
                    <h5>Upcoming Appointments</h5>
                </div>
                <div class="card-body">
                    @if (upcomingAppointments.Any())
                    {
                        <table class="table table-sm">
                            <thead>
                                <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th></tr>
                            </thead>
                            <tbody>
                                @foreach (var apt in upcomingAppointments.Take(5))
                                {
                                    <tr>
                                        <td>@apt.StartTime.ToString("MMM dd HH:mm")</td>
                                        <td>@apt.Pet.Name</td>
                                        <td>@apt.Pet.Owner.FullName</td>
                                        <td>@apt.Reason</td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                    else
                    {
                        <p class="text-muted">No upcoming appointments.</p>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">
                    <h5>Recent Invoices</h5>
                </div>
                <div class="card-body">
                    @if (recentInvoices.Any())
                    {
                        <table class="table table-sm">
                            <thead>
                                <tr><th>#</th><th>Owner</th><th>Total</th><th>Status</th></tr>
                            </thead>
                            <tbody>
                                @foreach (var inv in recentInvoices.Take(5))
                                {
                                    <tr>
                                        <td>@inv.Id</td>
                                        <td>@inv.Owner.FullName</td>
                                        <td>@inv.Total.ToString("C")</td>
                                        <td><span class="badge bg-@GetStatusColor(inv.Status)">@inv.Status</span></td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                    else
                    {
                        <p class="text-muted">No invoices yet.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool loading = true;
    private int petCount;
    private int ownerCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<Appointment> upcomingAppointments = [];
    private List<Invoice> recentInvoices = [];

    protected override async Task OnInitializedAsync()
    {
        var pets = await PatientService.GetAllPetsAsync();
        petCount = pets.Count;

        var owners = await PatientService.GetOwnersAsync();
        ownerCount = owners.Count;

        var today = DateTime.Today;
        var todayApts = await AppointmentService.GetAppointmentsAsync(today, today.AddDays(1));
        todayAppointments = todayApts.Count(a => a.Status == AppointmentStatus.Scheduled);

        upcomingAppointments = (await AppointmentService.GetAppointmentsAsync(DateTime.Now, DateTime.Now.AddDays(7)))
            .Where(a => a.Status == AppointmentStatus.Scheduled).ToList();

        var invoices = await BillingService.GetInvoicesAsync();
        pendingInvoices = invoices.Count(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid);
        recentInvoices = invoices.Take(5).ToList();

        loading = false;
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "secondary",
        _ => "secondary"
    };
}

