@page "/billing"
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer
@inject BillingService BillingService
@inject NavigationManager Navigation

<PageTitle>Billing - Invoices</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h3>Invoices</h3>
    <a href="/billing/invoice/new" class="btn btn-primary">Create Invoice</a>
</div>

<div class="mb-3">
    <label class="form-label me-2">Filter by Status:</label>
    <select class="form-select d-inline-block w-auto" @onchange="OnStatusFilterChanged">
        <option value="">All</option>
        <option value="Pending">Pending</option>
        <option value="Paid">Paid</option>
        <option value="PartiallyPaid">Partially Paid</option>
        <option value="Cancelled">Cancelled</option>
    </select>
</div>

@if (invoices == null)
{
    <p>Loading...</p>
}
else if (!invoices.Any())
{
    <p class="text-muted">No invoices found.</p>
}
else
{
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Invoice #</th>
                <th>Owner</th>
                <th>Date</th>
                <th>Total</th>
                <th>Paid</th>
                <th>Balance</th>
                <th>Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var invoice in invoices)
            {
                <tr style="cursor: pointer;" @onclick="() => ViewInvoice(invoice.Id)">
                    <td>@invoice.Id</td>
                    <td>@invoice.Owner?.FullName</td>
                    <td>@invoice.CreatedDate.ToShortDateString()</td>
                    <td>@invoice.Total.ToString("C")</td>
                    <td>@invoice.AmountPaid.ToString("C")</td>
                    <td>@invoice.Balance.ToString("C")</td>
                    <td><span class="badge bg-@GetStatusColor(invoice.Status)">@invoice.Status</span></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Invoice>? invoices;
    private InvoiceStatus? statusFilter;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        invoices = await BillingService.GetInvoicesAsync(statusFilter);
    }

    private async Task OnStatusFilterChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        statusFilter = string.IsNullOrEmpty(value) ? null : Enum.Parse<InvoiceStatus>(value);
        await LoadInvoices();
    }

    private void ViewInvoice(int id)
    {
        Navigation.NavigateTo($"/billing/invoice/{id}");
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "secondary",
        _ => "secondary"
    };
}

@page "/billing/invoice/{Id:int}"
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer
@inject BillingService BillingService
@inject NavigationManager Navigation

<PageTitle>Invoice Detail</PageTitle>

@if (invoice == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h3>Invoice #@invoice.Id</h3>
        <span class="badge bg-@GetStatusColor(invoice.Status) fs-6">@invoice.Status</span>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <p><strong>Owner:</strong> @invoice.Owner?.FullName</p>
            <p><strong>Created:</strong> @invoice.CreatedDate.ToShortDateString()</p>
            <p><strong>Due Date:</strong> @(invoice.DueDate?.ToShortDateString() ?? "N/A")</p>
        </div>
        <div class="col-md-6 text-end">
            <div class="card">
                <div class="card-body">
                    <h5>Total: @invoice.Total.ToString("C")</h5>
                    <p class="text-success mb-1">Paid: @invoice.AmountPaid.ToString("C")</p>
                    <p class="text-danger mb-0 fw-bold">Balance: @invoice.Balance.ToString("C")</p>
                </div>
            </div>
        </div>
    </div>

    <h5>Line Items</h5>
    <table class="table">
        <thead>
            <tr>
                <th>Description</th>
                <th>Qty</th>
                <th>Unit Price</th>
                <th>Line Total</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @if (invoice.LineItems != null)
            {
                @foreach (var item in invoice.LineItems)
                {
                    <tr>
                        <td>@item.Description</td>
                        <td>@item.Quantity</td>
                        <td>@item.Amount.ToString("C")</td>
                        <td>@((item.Amount * item.Quantity).ToString("C"))</td>
                        <td>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveLineItem(item.Id)">Remove</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>

    <div class="card mb-4">
        <div class="card-body">
            <h6>Add Line Item</h6>
            <div class="row g-2 align-items-end">
                <div class="col-md-4">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newItemDescription" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Amount</label>
                    <input type="number" step="0.01" class="form-control" @bind="newItemAmount" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Quantity</label>
                    <input type="number" class="form-control" @bind="newItemQuantity" />
                </div>
                <div class="col-md-2">
                    <button class="btn btn-success" @onclick="AddLineItem">Add</button>
                </div>
            </div>
        </div>
    </div>

    <h5>Payment History</h5>
    @if (invoice.Payments != null && invoice.Payments.Any())
    {
        <table class="table">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Amount</th>
                    <th>Method</th>
                    <th>Reference</th>
                    <th>Refunded</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var payment in invoice.Payments)
                {
                    <tr>
                        <td>@payment.PaidDate.ToShortDateString()</td>
                        <td>@payment.Amount.ToString("C")</td>
                        <td>@payment.Method</td>
                        <td>@(payment.Reference ?? "—")</td>
                        <td>@(payment.IsRefunded ? "Yes" : "No")</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    else
    {
        <p class="text-muted">No payments recorded.</p>
    }

    @if (!showPaymentForm)
    {
        <button class="btn btn-primary mt-2" @onclick="() => showPaymentForm = true">Record Payment</button>
    }
    else
    {
        <div class="card mt-3">
            <div class="card-body">
                <h6>Record Payment</h6>
                <div class="row g-2">
                    <div class="col-md-3">
                        <label class="form-label">Amount</label>
                        <input type="number" step="0.01" class="form-control" @bind="paymentAmount" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="paymentMethod">
                            @foreach (var method in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@method">@method</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reference</label>
                        <input type="text" class="form-control" @bind="paymentReference" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Date</label>
                        <input type="date" class="form-control" @bind="paymentDate" />
                    </div>
                </div>
                <div class="mt-3">
                    <button class="btn btn-success me-2" @onclick="SubmitPayment">Submit Payment</button>
                    <button class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    <div class="mt-4">
        <a href="/billing" class="btn btn-outline-secondary">Back to Invoices</a>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Invoice? invoice;

    private string newItemDescription = "";
    private decimal newItemAmount;
    private int newItemQuantity = 1;

    private bool showPaymentForm;
    private decimal paymentAmount;
    private PaymentMethod paymentMethod = PaymentMethod.Cash;
    private string? paymentReference;
    private DateTime paymentDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await BillingService.GetInvoiceAsync(Id);
        if (invoice != null)
        {
            paymentAmount = invoice.Balance;
        }
    }

    private async Task AddLineItem()
    {
        if (string.IsNullOrWhiteSpace(newItemDescription) || newItemAmount <= 0 || newItemQuantity <= 0)
            return;

        var item = new InvoiceLineItem
        {
            InvoiceId = Id,
            Description = newItemDescription,
            Amount = newItemAmount,
            Quantity = newItemQuantity
        };

        await BillingService.AddLineItemAsync(item);
        newItemDescription = "";
        newItemAmount = 0;
        newItemQuantity = 1;
        await LoadInvoice();
    }

    private async Task RemoveLineItem(int itemId)
    {
        await BillingService.RemoveLineItemAsync(itemId);
        await LoadInvoice();
    }

    private async Task SubmitPayment()
    {
        if (paymentAmount <= 0)
            return;

        var payment = new Payment
        {
            InvoiceId = Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            PaidDate = paymentDate,
            Reference = paymentReference
        };

        await BillingService.ProcessPaymentAsync(payment);
        showPaymentForm = false;
        paymentReference = null;
        await LoadInvoice();
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "secondary",
        _ => "secondary"
    };
}

@page "/billing/invoice/new"
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer
@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Create Invoice</PageTitle>

<h3>Create Invoice</h3>

<div class="row mb-3">
    <div class="col-md-6">
        <label class="form-label">Owner</label>
        <select class="form-select" @bind="selectedOwnerId">
            <option value="0">-- Select Owner --</option>
            @if (owners != null)
            {
                @foreach (var owner in owners)
                {
                    <option value="@owner.Id">@owner.FullName</option>
                }
            }
        </select>
    </div>
    <div class="col-md-6">
        <label class="form-label">Due Date</label>
        <input type="date" class="form-control" @bind="dueDate" />
    </div>
</div>

<h5>Line Items</h5>
<table class="table">
    <thead>
        <tr>
            <th>Description</th>
            <th>Amount</th>
            <th>Quantity</th>
            <th>Subtotal</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @for (int i = 0; i < lineItems.Count; i++)
        {
            var index = i;
            <tr>
                <td>
                    <input type="text" class="form-control" @bind="lineItems[index].Description" />
                </td>
                <td>
                    <input type="number" step="0.01" class="form-control" @bind="lineItems[index].Amount" />
                </td>
                <td>
                    <input type="number" class="form-control" @bind="lineItems[index].Quantity" />
                </td>
                <td>@((lineItems[index].Amount * lineItems[index].Quantity).ToString("C"))</td>
                <td>
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveLineItem(index)">Remove</button>
                </td>
            </tr>
        }
    </tbody>
</table>

<button class="btn btn-outline-primary mb-3" @onclick="AddLineItem">+ Add Line Item</button>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="mb-0">Running Total: @RunningTotal.ToString("C")</h5>
    </div>
</div>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="d-flex gap-2">
    <button class="btn btn-success" @onclick="SaveInvoice" disabled="@isSaving">
        @(isSaving ? "Saving..." : "Save Invoice")
    </button>
    <a href="/billing" class="btn btn-secondary">Cancel</a>
</div>

@code {
    private List<Owner>? owners;
    private int selectedOwnerId;
    private DateTime? dueDate = DateTime.Today.AddDays(30);
    private List<InvoiceLineItem> lineItems = new() { new InvoiceLineItem { Quantity = 1 } };
    private string? errorMessage;
    private bool isSaving;

    private decimal RunningTotal => lineItems.Sum(li => li.Amount * li.Quantity);

    protected override async Task OnInitializedAsync()
    {
        owners = await PatientService.GetOwnersAsync();
    }

    private void AddLineItem()
    {
        lineItems.Add(new InvoiceLineItem { Quantity = 1 });
    }

    private void RemoveLineItem(int index)
    {
        if (lineItems.Count > 1)
        {
            lineItems.RemoveAt(index);
        }
    }

    private async Task SaveInvoice()
    {
        errorMessage = null;

        if (selectedOwnerId == 0)
        {
            errorMessage = "Please select an owner.";
            return;
        }

        if (!lineItems.Any(li => !string.IsNullOrWhiteSpace(li.Description) && li.Amount > 0))
        {
            errorMessage = "Please add at least one valid line item.";
            return;
        }

        isSaving = true;

        try
        {
            var invoice = new Invoice
            {
                OwnerId = selectedOwnerId,
                CreatedDate = DateTime.Now,
                DueDate = dueDate,
                Status = InvoiceStatus.Pending,
                LineItems = lineItems
                    .Where(li => !string.IsNullOrWhiteSpace(li.Description) && li.Amount > 0)
                    .ToList()
            };

            var created = await BillingService.CreateInvoiceAsync(invoice);
            Navigation.NavigateTo($"/billing/invoice/{created.Id}");
        }
        catch (Exception ex)
        {
            errorMessage = $"Error creating invoice: {ex.Message}";
            isSaving = false;
        }
    }
}

@page "/billing/payments"
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer
@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Payment History</PageTitle>

<h3>Payment History</h3>

<div class="mb-3">
    <label class="form-label me-2">Filter by Owner:</label>
    <select class="form-select d-inline-block w-auto" @onchange="OnOwnerFilterChanged">
        <option value="">All Owners</option>
        @if (owners != null)
        {
            @foreach (var owner in owners)
            {
                <option value="@owner.Id">@owner.FullName</option>
            }
        }
    </select>
</div>

@if (payments == null)
{
    <p>Loading...</p>
}
else if (!payments.Any())
{
    <p class="text-muted">No payments found.</p>
}
else
{
    <table class="table table-hover">
        <thead>
            <tr>
                <th style="cursor: pointer;" @onclick="ToggleSortByDate">
                    Date @(sortAscending ? "▲" : "▼")
                </th>
                <th>Invoice #</th>
                <th>Owner</th>
                <th>Amount</th>
                <th>Method</th>
                <th>Reference</th>
                <th>Refunded</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var payment in sortedPayments)
            {
                <tr>
                    <td>@payment.PaidDate.ToShortDateString()</td>
                    <td>
                        <a href="/billing/invoice/@payment.InvoiceId">@payment.InvoiceId</a>
                    </td>
                    <td>@payment.Invoice?.Owner?.FullName</td>
                    <td>@payment.Amount.ToString("C")</td>
                    <td>@payment.Method</td>
                    <td>@(payment.Reference ?? "—")</td>
                    <td>
                        @if (payment.IsRefunded)
                        {
                            <span class="badge bg-danger">Yes</span>
                        }
                        else
                        {
                            <span class="text-muted">No</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Payment>? payments;
    private List<Owner>? owners;
    private int? ownerFilter;
    private bool sortAscending;

    private IEnumerable<Payment> sortedPayments =>
        sortAscending
            ? payments!.OrderBy(p => p.PaidDate)
            : payments!.OrderByDescending(p => p.PaidDate);

    protected override async Task OnInitializedAsync()
    {
        owners = await PatientService.GetOwnersAsync();
        await LoadPayments();
    }

    private async Task LoadPayments()
    {
        payments = await BillingService.GetPaymentHistoryAsync(ownerFilter);
    }

    private async Task OnOwnerFilterChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        ownerFilter = string.IsNullOrEmpty(value) ? null : int.Parse(value);
        await LoadPayments();
    }

    private void ToggleSortByDate()
    {
        sortAscending = !sortAscending;
    }
}

