    <div class="row mb-4">
        <div class="col-md-6">
            <p><strong>Owner:</strong> @invoice.Owner?.FullName</p>
            <p><strong>Created:</strong> @invoice.CreatedDate.ToShortDateString()</p>
            <p><strong>Due Date:</strong> @(invoice.DueDate?.ToShortDateString() ?? "N/A")</p>
        </div>
        <div class="col-md-6 text-end">
            <div class="card">
                <div class="card-body">
                    <h5>Total: @invoice.Total.ToString("C")</h5>
                    <p class="text-success mb-1">Paid: @invoice.AmountPaid.ToString("C")</p>
                    <p class="text-danger mb-0 fw-bold">Balance: @invoice.Balance.ToString("C")</p>
                </div>
            </div>
        </div>
    </div>

    <h5>Line Items</h5>
    <table class="table">
        <thead>
            <tr>
                <th>Description</th>
                <th>Qty</th>
                <th>Unit Price</th>
                <th>Line Total</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @if (invoice.LineItems != null)
            {
                @foreach (var item in invoice.LineItems)
                {
                    <tr>
                        <td>@item.Description</td>
                        <td>@item.Quantity</td>
                        <td>@item.Amount.ToString("C")</td>
                        <td>@((item.Amount * item.Quantity).ToString("C"))</td>
                        <td>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveLineItem(item.Id)">Remove</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>

    <div class="card mb-4">
        <div class="card-body">
            <h6>Add Line Item</h6>
            <div class="row g-2 align-items-end">
                <div class="col-md-4">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newItemDescription" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Amount</label>
                    <input type="number" step="0.01" class="form-control" @bind="newItemAmount" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Quantity</label>
                    <input type="number" class="form-control" @bind="newItemQuantity" />
                </div>
                <div class="col-md-2">
                    <button class="btn btn-success" @onclick="AddLineItem">Add</button>
                </div>
            </div>
