    protected override async Task OnInitializedAsync()
    {
        if (!IsNew)
        {
            var existing = await PatientService.GetPetAsync(Id);
            if (existing != null)
            {
                pet = existing;
                OwnerId = pet.OwnerId;
                ownerDisplay = pet.Owner.FullName;
            }
        }
        else
        {
            pet.OwnerId = OwnerId;
            var owner = await PatientService.GetOwnerAsync(OwnerId);
            ownerDisplay = owner?.FullName ?? "";
        }
    }

    private async Task SaveAsync()
    {
        pet.OwnerId = OwnerId;
        var saved = await PatientService.SavePetAsync(pet);
        Navigation.NavigateTo($"/patients/pet/{saved.Id}/detail");
    }

    private void Cancel()
    {
        if (!IsNew)
            Navigation.NavigateTo($"/patients/pet/{Id}/detail");
        else
            Navigation.NavigateTo($"/patients/owner/{OwnerId}");
    }
}

