@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Pet Detail</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h3>@pet.Name</h3>
        <button class="btn btn-outline-primary" @onclick="() => Navigation.NavigateTo($"/patients/pet/{Id}")">Edit Pet</button>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Pet Information</div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Species</dt>
                        <dd class="col-sm-8">@pet.Species</dd>
                        <dt class="col-sm-4">Breed</dt>
                        <dd class="col-sm-8">@(pet.Breed ?? "—")</dd>
                        <dt class="col-sm-4">Date of Birth</dt>
                        <dd class="col-sm-8">@(pet.DateOfBirth?.ToString("yyyy-MM-dd") ?? "—")</dd>
                        <dt class="col-sm-4">Weight</dt>
                        <dd class="col-sm-8">@(pet.WeightKg.HasValue ? $"{pet.WeightKg} kg" : "—")</dd>
                        <dt class="col-sm-4">Microchip</dt>
                        <dd class="col-sm-8">@(pet.Microchip ?? "—")</dd>
                    </dl>
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Owner Information</div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Name</dt>
                        <dd class="col-sm-8">@pet.Owner.FullName</dd>
                        <dt class="col-sm-4">Phone</dt>
                        <dd class="col-sm-8">@(pet.Owner.Phone ?? "—")</dd>
                        <dt class="col-sm-4">Email</dt>
                        <dd class="col-sm-8">@(pet.Owner.Email ?? "—")</dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>

    <div class="d-flex justify-content-between align-items-center mb-3">
        <h4>Medical History</h4>
        <button class="btn btn-success" @onclick="ShowAddForm">
            <i class="bi bi-plus-circle"></i> Add Treatment Note
        </button>
    </div>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5>@(editingNoteId.HasValue ? "Edit Treatment Note" : "New Treatment Note")</h5>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Date</label>
                        <input type="datetime-local" class="form-control" @bind="noteDate" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Title</label>
                        <input type="text" class="form-control" @bind="noteTitle" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Veterinarian</label>
                        <input type="text" class="form-control" @bind="noteVet" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="3" @bind="noteDescription"></textarea>
                </div>
                <div class="d-flex gap-2">
                    <button class="btn btn-primary" @onclick="SaveNoteAsync">Save</button>
                    <button class="btn btn-secondary" @onclick="CancelNote">Cancel</button>
                </div>
            </div>
        </div>
    }

    @if (!pet.TreatmentNotes.Any())
    {
        <p class="text-muted">No treatment notes recorded.</p>
    }
    else
    {
        @foreach (var note in pet.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <div>
                            <h6 class="card-title mb-1">@note.Title</h6>
                            <small class="text-muted">@note.Date.ToString("yyyy-MM-dd HH:mm") — @(note.Veterinarian ?? "Unknown")</small>
                        </div>
                        <div>
                            <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditNote(note)">Edit</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => ConfirmDelete(note.Id)">Delete</button>
                        </div>
                    </div>
                    <p class="card-text mt-2 mb-0">@note.Description</p>
                </div>
            </div>
        }
    }

    @if (deleteConfirmId.HasValue)
    {
        <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Confirm Delete</h5>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to delete this treatment note?</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="() => deleteConfirmId = null">Cancel</button>
                        <button class="btn btn-danger" @onclick="DeleteNoteAsync">Delete</button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private bool showNoteForm;
    private int? editingNoteId;
    private int? deleteConfirmId;

    private DateTime noteDate = DateTime.Now;
    private string noteTitle = "";
    private string noteDescription = "";
    private string? noteVet;

    protected override async Task OnInitializedAsync()
    {
        await LoadPetAsync();
    }

    private async Task LoadPetAsync()
    {
        pet = await PatientService.GetPetAsync(Id);
    }

    private void ShowAddForm()
    {
        editingNoteId = null;
        noteDate = DateTime.Now;
        noteTitle = "";
        noteDescription = "";
        noteVet = "";
        showNoteForm = true;
    }

    private void EditNote(TreatmentNote note)
    {
        editingNoteId = note.Id;
        noteDate = note.Date;
        noteTitle = note.Title;
        noteDescription = note.Description;
        noteVet = note.Veterinarian;
        showNoteForm = true;
    }

    private void CancelNote()
    {
        showNoteForm = false;
        editingNoteId = null;
    }

    private async Task SaveNoteAsync()
    {
        if (editingNoteId.HasValue)
        {
            await PatientService.UpdateTreatmentNoteAsync(new TreatmentNote
            {
                Id = editingNoteId.Value,
                PetId = Id,
                Date = noteDate,
                Title = noteTitle,
                Description = noteDescription,
                Veterinarian = noteVet
            });
        }
        else
        {
            await PatientService.AddTreatmentNoteAsync(new TreatmentNote
            {
                PetId = Id,
                Date = noteDate,
                Title = noteTitle,
                Description = noteDescription,
                Veterinarian = noteVet
            });
        }

        showNoteForm = false;
        editingNoteId = null;
        await LoadPetAsync();
    }

    private void ConfirmDelete(int noteId)
    {
        deleteConfirmId = noteId;
    }

    private async Task DeleteNoteAsync()
    {
        if (deleteConfirmId.HasValue)
        {
            await PatientService.DeleteTreatmentNoteAsync(deleteConfirmId.Value);
            deleteConfirmId = null;
            await LoadPetAsync();
        }
    }
}

