@page "/appointments"
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer
@inject AppointmentService AppointmentService
@inject NavigationManager Navigation

<PageTitle>Appointments</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h3>Appointments</h3>
    <a href="/appointments/new" class="btn btn-primary">
        <i class="bi bi-plus-circle"></i> New Appointment
    </a>
</div>

<div class="d-flex justify-content-between align-items-center mb-3">
    <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous</button>
    <h5 class="mb-0">@weekStart.ToString("MMM d") &ndash; @weekEnd.ToString("MMM d, yyyy")</h5>
    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
</div>

<div class="table-responsive">
    <table class="table table-bordered table-sm">
        <thead class="table-light">
            <tr>
                <th style="width:70px;">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="text-center">@day.ToString("ddd MM/dd")</th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int slot = 0; slot < timeSlots.Count; slot++)
            {
                var time = timeSlots[slot];
                <tr>
                    <td class="text-nowrap small">@time.ToString(@"hh\:mm")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotStart = day.Add(time);
                        var appt = GetAppointmentAt(slotStart);
                        var isOccupied = IsSlotOccupied(slotStart);

                        if (appt != null && appt.StartTime == slotStart)
                        {
                            var rowSpan = GetRowSpan(appt);
                            var cssClass = GetStatusClass(appt.Status);
                            <td rowspan="@rowSpan" class="@cssClass p-1 cursor-pointer" style="vertical-align:top; cursor:pointer;" @onclick="() => ShowDetails(appt)">
                                <small class="fw-bold">@appt.Pet?.Name</small><br/>
                                <small>@appt.Reason</small>
                            </td>
                        }
                        else if (appt == null && !IsWithinExistingAppointment(slotStart))
                        {
                            <td class="@(isOccupied ? "table-warning" : "")" style="cursor:pointer;" @onclick="() => CreateAtSlot(slotStart)">
                            </td>
                        }
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@if (selectedAppointment != null)
{
    <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5);">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Appointment Details</h5>
                    <button type="button" class="btn-close" @onclick="CloseDetails"></button>
                </div>
                <div class="modal-body">
                    <p><strong>Pet:</strong> @selectedAppointment.Pet?.Name (@selectedAppointment.Pet?.Species)</p>
                    <p><strong>Owner:</strong> @selectedAppointment.Pet?.Owner?.FullName</p>
                    <p><strong>Date:</strong> @selectedAppointment.StartTime.ToString("g") &ndash; @selectedAppointment.EndTime.ToString("t")</p>
                    <p><strong>Reason:</strong> @selectedAppointment.Reason</p>
                    <p><strong>Veterinarian:</strong> @(selectedAppointment.Veterinarian ?? "N/A")</p>
                    <p><strong>Status:</strong> <span class="badge @GetBadgeClass(selectedAppointment.Status)">@selectedAppointment.Status</span></p>
                    @if (!string.IsNullOrEmpty(selectedAppointment.Notes))
                    {
                        <p><strong>Notes:</strong> @selectedAppointment.Notes</p>
                    }
                </div>
                <div class="modal-footer">
                    @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
                    {
                        <a href="/appointments/@selectedAppointment.Id" class="btn btn-warning">Reschedule</a>
                        <button class="btn btn-danger" @onclick="CancelAppointment">Cancel Appointment</button>
                    }
                    <button class="btn btn-secondary" @onclick="CloseDetails">Close</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private DateTime weekStart;
    private DateTime weekEnd;
    private List<TimeSpan> timeSlots = new();
    private List<Appointment> appointments = new();
    private Appointment? selectedAppointment;

    protected override async Task OnInitializedAsync()
    {
        SetCurrentWeek(DateTime.Today);
        GenerateTimeSlots();
        await LoadAppointments();
    }

    private void GenerateTimeSlots()
    {
        timeSlots.Clear();
        for (int h = 8; h < 18; h++)
        {
            timeSlots.Add(new TimeSpan(h, 0, 0));
            timeSlots.Add(new TimeSpan(h, 30, 0));
        }
    }

    private void SetCurrentWeek(DateTime date)
    {
        var diff = (int)date.DayOfWeek - (int)DayOfWeek.Monday;
        if (diff < 0) diff += 7;
        weekStart = date.AddDays(-diff).Date;
        weekEnd = weekStart.AddDays(6);
    }

    private async Task LoadAppointments()
    {
        appointments = await AppointmentService.GetAppointmentsAsync(weekStart, weekEnd.AddDays(1));
    }

    private async Task PreviousWeek()
    {
        SetCurrentWeek(weekStart.AddDays(-7));
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        SetCurrentWeek(weekStart.AddDays(7));
        await LoadAppointments();
    }

    private Appointment? GetAppointmentAt(DateTime slotStart)
    {
        return appointments.FirstOrDefault(a => a.StartTime == slotStart);
    }

    private bool IsSlotOccupied(DateTime slotStart)
    {
        var slotEnd = slotStart.AddMinutes(30);
        return appointments.Any(a => a.Status == AppointmentStatus.Scheduled && a.StartTime < slotEnd && a.EndTime > slotStart);
    }

    private bool IsWithinExistingAppointment(DateTime slotStart)
    {
        return appointments.Any(a => a.StartTime < slotStart && a.EndTime > slotStart);
    }

    private int GetRowSpan(Appointment appt)
    {
        var duration = (appt.EndTime - appt.StartTime).TotalMinutes;
