+@page "/appointments/new"
+@page "/appointments/{Id:int}"
+@using VetClinic.Data.Models
+@using VetClinic.Services
+@using Microsoft.AspNetCore.Authorization
+@attribute [Authorize]
+@rendermode InteractiveServer
+@inject AppointmentService AppointmentService
+@inject PatientService PatientService
+@inject NavigationManager Navigation
+
+<PageTitle>@(IsEdit ? "Edit Appointment" : "New Appointment")</PageTitle>
+
+<h3 class="mb-3">@(IsEdit ? "Reschedule Appointment" : "New Appointment")</h3>
+
+@if (!string.IsNullOrEmpty(errorMessage))
+{
+    <div class="alert alert-danger">@errorMessage</div>
+}
+
+@if (!string.IsNullOrEmpty(warningMessage))
+{
+    <div class="alert alert-warning">@warningMessage</div>
+}
+
+<div class="row">
+    <div class="col-md-8">
+        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="appointmentForm">
+            <DataAnnotationsValidator />
+            <ValidationSummary class="text-danger" />
+
+            <div class="mb-3">
+                <label class="form-label">Pet</label>
+                <input type="text" class="form-control" placeholder="Search pet..."
+                       @bind="petSearchText" @bind:event="oninput" @onfocus="() => showPetDropdown = true" />
+                @if (showPetDropdown && filteredPets.Any())
+                {
+                    <div class="list-group position-absolute z-3" style="max-height:200px; overflow-y:auto; width:100%;">
+                        @foreach (var pet in filteredPets.Take(10))
+                        {
+                            <button type="button" class="list-group-item list-group-item-action"
+                                    @onclick="() => SelectPet(pet)">
+                                @pet.Name - @pet.Owner?.FullName (@pet.Species)
+                            </button>
+                        }
+                    </div>
+                }
+                @if (model.PetId > 0)
+                {
+                    <small class="text-success">Selected: @petSearchText</small>
+                }
+            </div>
+
+            <div class="mb-3">
+                <label class="form-label">Date</label>
+                <input type="date" class="form-control" @bind="selectedDate" />
+            </div>
+
+            <div class="row mb-3">
+                <div class="col-md-6">
+                    <label class="form-label">Start Time</label>
+                    <select class="form-select" @bind="selectedTime">
+                        @foreach (var time in timeOptions)
+                        {
+                            <option value="@time">@time.ToString(@"hh\:mm")</option>
+                        }
+                    </select>
+                </div>
+                <div class="col-md-6">
+                    <label class="form-label">Duration</label>
+                    <select class="form-select" @bind="selectedDuration">
+                        <option value="30">30 minutes</option>
+                        <option value="60">60 minutes</option>
+                        <option value="90">90 minutes</option>
+                    </select>
+                </div>
+            </div>
+
+            <div class="mb-3">
+                <label class="form-label">Reason</label>
+                <input type="text" class="form-control" @bind="model.Reason" required />
+            </div>
+
+            <div class="mb-3">
+                <label class="form-label">Veterinarian</label>
+                <input type="text" class="form-control" @bind="model.Veterinarian" />
+            </div>
+
+            <div class="mb-3">
+                <label class="form-label">Notes</label>
+                <textarea class="form-control" rows="3" @bind="model.Notes"></textarea>
+            </div>
+
+            <div class="mb-3">
+                <button type="button" class="btn btn-info me-2" @onclick="CheckAvailability">Check Availability</button>
+                @if (availabilityChecked && isAvailable)
+                {
+                    <span class="text-success fw-bold">&#10003; Slot available</span>
+                }
+            </div>
+
+            <div class="d-flex gap-2">
+                <button type="submit" class="btn btn-primary" disabled="@isSaving">
+                    @(isSaving ? "Saving..." : (IsEdit ? "Update Appointment" : "Create Appointment"))
+                </button>
+                <a href="/appointments" class="btn btn-secondary">Cancel</a>
+            </div>
+        </EditForm>
+    </div>
+</div>
+
+@code {
+    [Parameter] public int? Id { get; set; }
+
+    [SupplyParameterFromQuery(Name = "date")]
+    public string? PreselectedDate { get; set; }
+
+    private bool IsEdit => Id.HasValue;
+
+    private Appointment model = new();
+    private List<Pet> pets = new();
+    private string petSearchText = "";
+    private bool showPetDropdown;
+    private DateTime selectedDate = DateTime.Today;
+    private TimeSpan selectedTime = new(9, 0, 0);
+    private int selectedDuration = 30;
+    private string? errorMessage;
+    private string? warningMessage;
+    private bool availabilityChecked;
+    private bool isAvailable;
+    private bool isSaving;
+
+    private List<TimeSpan> timeOptions = new();
+
+    private IEnumerable<Pet> filteredPets => string.IsNullOrWhiteSpace(petSearchText)
+        ? pets
+        : pets.Where(p =>
+            p.Name.Contains(petSearchText, StringComparison.OrdinalIgnoreCase) ||
+            (p.Owner?.FullName?.Contains(petSearchText, StringComparison.OrdinalIgnoreCase) ?? false));
+
+    protected override async Task OnInitializedAsync()
+    {
+        GenerateTimeOptions();
+        pets = await PatientService.GetAllPetsAsync();
+
+        if (IsEdit)
+        {
+            var existing = await AppointmentService.GetAppointmentAsync(Id!.Value);
+            if (existing == null)
+            {
+                Navigation.NavigateTo("/appointments");
+                return;
+            }
+            model = existing;
+            selectedDate = existing.StartTime.Date;
+            selectedTime = existing.StartTime.TimeOfDay;
+            selectedDuration = (int)(existing.EndTime - existing.StartTime).TotalMinutes;
+            var pet = pets.FirstOrDefault(p => p.Id == existing.PetId);
+            if (pet != null)
+            {
+                petSearchText = $"{pet.Name} - {pet.Owner?.FullName}";
+            }
+        }
+        else if (!string.IsNullOrEmpty(PreselectedDate) && DateTime.TryParse(PreselectedDate, out var parsed))
+        {
+            selectedDate = parsed.Date;
+            selectedTime = parsed.TimeOfDay;
+        }
+    }
+
+    private void GenerateTimeOptions()
+    {
+        for (int h = 8; h <= 17; h++)
+        {
+            timeOptions.Add(new TimeSpan(h, 0, 0));
+            if (h < 17 || h == 17)
+                timeOptions.Add(new TimeSpan(h, 30, 0));
+        }
+        // Remove 18:00 - last valid start is 17:30
+        timeOptions = timeOptions.Where(t => t < new TimeSpan(18, 0, 0)).ToList();
+    }
+
+    private void SelectPet(Pet pet)
+    {
+        model.PetId = pet.Id;
+        petSearchText = $"{pet.Name} - {pet.Owner?.FullName}";
+        showPetDropdown = false;
+    }
+
+    private async Task CheckAvailability()
+    {
+        warningMessage = null;
+        var start = selectedDate.Add(selectedTime);
+        var end = start.AddMinutes(selectedDuration);
+        isAvailable = await AppointmentService.IsSlotAvailableAsync(start, end, IsEdit ? Id : null);
+        availabilityChecked = true;
+
+        if (!isAvailable)
+        {
+            warningMessage = "This time slot is already occupied. Please choose a different time.";
+        }
+    }
+
+    private async Task HandleSubmit()
+    {
+        errorMessage = null;
+        warningMessage = null;
+
+        if (model.PetId <= 0)
+        {
+            errorMessage = "Please select a pet.";
+            return;
+        }
+
+        if (string.IsNullOrWhiteSpace(model.Reason))
+        {
+            errorMessage = "Please provide a reason for the appointment.";
+            return;
+        }
+
+        model.StartTime = selectedDate.Add(selectedTime);
+        model.EndTime = model.StartTime.AddMinutes(selectedDuration);
+
+        // Validate end time doesn't exceed clinic hours
+        if (model.EndTime.TimeOfDay > new TimeSpan(18, 0, 0))
+        {
+            errorMessage = "Appointment cannot extend beyond 18:00.";
+            return;
+        }
+
+        var available = await AppointmentService.IsSlotAvailableAsync(model.StartTime, model.EndTime, IsEdit ? Id : null);
+        if (!available)
+        {
+            warningMessage = "This time slot is already occupied. Please choose a different time.";
+            return;
+        }
+
+        isSaving = true;
+        try
+        {
+            await AppointmentService.SaveAppointmentAsync(model);
+            Navigation.NavigateTo("/appointments");
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Error saving appointment: {ex.Message}";
+            isSaving = false;
+        }
+    }
+}
+

